	if (hist_u) {
		do {
			lo = &lb->hist[hist_u - 1];
			useq = lo->seq;
			while (hist_u && lb->hist[hist_u - 1].seq == useq)
				lo = &lb->hist[--hist_u];
		} while (hist_u && hist_u >= last_hist_u);
		last_hist_u = hist_u;
		hist_u = lb->hist_u;
		while (hist_u != last_hist_u) {
			lo = &lb->hist[--hist_u];
			if (lb->hist[last_hist_u].pos > lo->pos) {
				rpos += lo->n_ins;
				rpos -= lo->n_del;
			}
		}
	} else
		return ret ? ret : 1;
	*pos = rpos + lb->hist[last_hist_u].pos;
	*off = lo->pos_off;
	return ret;
}

